#include <iostream>

class GradeList {
    int m_grades[5]{};
public:
    void set(int index, int value) { m_grades[index] = value; }
    int get(int index) const { return m_grades[index]; }

    int& operator[](int index) { return m_grades[index]; }

    int operator[](int index) const { return m_grades[index]; }
};

void printGrade(const GradeList& list, int index) {
    std::cout << list[index] << '\n';
}

int main() {
    GradeList grades;
    for (int i{ 0 }; i < 5; ++i) {
        int g{};
        std::cin >> g;
        grades.set(i, g);
    }

    int index{};
    int newGrade{};
    std::cin >> index >> newGrade;

    printGrade(grades, index);
    grades[index] = newGrade;
    printGrade(grades, index);

    return 0;
}

