#include <iostream>
#include <string>

class NameTable {
    std::string m_names[10];
    int m_size{};
public:
    void add(const std::string& name) { m_names[m_size++] = name; }
    const std::string& get(int index) const { return m_names[index]; }
    void setAt(int index, const std::string& val) { m_names[index] = val; }

    std::string& operator[](int index) { return m_names[index]; }

    const std::string& operator[](int index) const { return m_names[index]; }
};

int main() {
    NameTable table;
    int n{};
    std::cin >> n;
    for (int i{ 0 }; i < n; ++i) {
        std::string name;
        std::cin >> name;
        table.add(name);
    }

    int readIndex{};
    int swapA{};
    int swapB{};
    std::cin >> readIndex >> swapA >> swapB;

    const NameTable& constRef{ table };
    std::cout << constRef[readIndex] << '\n';

    std::string temp{ table[swapA] };
    table[swapA] = table[swapB];
    table[swapB] = temp;

    std::cout << table[swapA] << '\n';
    std::cout << table[swapB] << '\n';

    return 0;
}
